{
  "name": "reminder-temporal",
  "version": "1.0.0",
  "description": "Durable Reminder workflow on Temporal Cloud (TypeScript)",
  "main": "lib/client.js",
  "scripts": {
    "build": "tsc --build",
    "start": "npm run build && node lib/start.js"
  },
  "dependencies": {
    "@temporalio/activity": "^1.11.4",
    "@temporalio/client": "^1.11.4",
    "@temporalio/worker": "^1.11.4",
    "@temporalio/workflow": "^1.11.4"
  },
  "devDependencies": {
    "typescript": "^5.4.5"
  }
}

import * as fs from 'fs';
import * as path from 'path';

const LOG_FILE = '/workspace/reminder.log';

/**
 * Notify activity: appends "Notified: <message>" to the log file and returns the string.
 */
export async function Notify(message: string): Promise<string> {
  const line = `Notified: ${message}`;

  // Ensure parent directory exists
  const dir = path.dirname(LOG_FILE);
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }

  fs.appendFileSync(LOG_FILE, line + '\n', 'utf8');

  return line;
}

import { sleep, proxyActivities } from '@temporalio/workflow';
import type * as activities from './activities';

// Proxy the Notify activity with a reasonable timeout
const { Notify } = proxyActivities<typeof activities>({
  startToCloseTimeout: '30 seconds',
});

export interface ReminderInput {
  message: string;
  delaySeconds: number;
}

/**
 * ReminderWorkflow: sleeps for delaySeconds, then calls Notify and returns its result.
 */
export async function ReminderWorkflow(input: ReminderInput): Promise<string> {
  const { message, delaySeconds } = input;

  // Deterministic sleep inside the workflow sandbox
  await sleep(delaySeconds * 1000);

  // Invoke the Notify activity and return the result
  return await Notify(message);
}

import { Worker, NativeConnection } from '@temporalio/worker';
import * as activities from './activities';
import * as path from 'path';

async function main(): Promise<void> {
  const apiKey = process.env.TEMPORAL_API_KEY;
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;

  if (!apiKey || !address || !namespace) {
    throw new Error(
      'Missing required environment variables: TEMPORAL_API_KEY, TEMPORAL_ADDRESS, TEMPORAL_NAMESPACE'
    );
  }

  // Connect to Temporal Cloud using API key + TLS
  const connection = await NativeConnection.connect({
    address,
    tls: true,
    apiKey,
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: 'reminder-ts',
    // Point the bundler at our compiled workflow file
    workflowsPath: path.join(__dirname, 'workflows'),
    activities,
  });

  console.log('Worker started, polling task queue "reminder-ts"...');
  await worker.run();
}

main().catch((err) => {
  console.error('Worker failed:', err);
  process.exit(1);
});

import { Connection, Client } from '@temporalio/client';
import { ReminderWorkflow } from './workflows';

async function main(): Promise<void> {
  const apiKey = process.env.TEMPORAL_API_KEY;
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const runId = process.env.ZEALT_RUN_ID;

  if (!apiKey || !address || !namespace) {
    throw new Error(
      'Missing required environment variables: TEMPORAL_API_KEY, TEMPORAL_ADDRESS, TEMPORAL_NAMESPACE'
    );
  }

  if (!runId) {
    throw new Error('Missing required environment variable: ZEALT_RUN_ID');
  }

  // Connect to Temporal Cloud using API key + TLS
  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
  });

  const client = new Client({
    connection,
    namespace,
  });

  const workflowId = `reminder-${runId}`;

  console.log(`Starting ReminderWorkflow with ID: ${workflowId}`);

  const handle = await client.workflow.start(ReminderWorkflow, {
    taskQueue: 'reminder-ts',
    workflowId,
    args: [{ message: 'wake up', delaySeconds: 3 }],
  });

  console.log(`Workflow started, waiting for result...`);

  const result = await handle.result();
  console.log(result);

  await connection.close();
}

main().catch((err) => {
  console.error('Client failed:', err);
  process.exit(1);
});

/**
 * start.ts — orchestrates the Worker (background) + Client (foreground).
 *
 * Spawns the worker as a child process, waits briefly for it to come up,
 * then runs the client in-process. Once the client exits the worker is killed.
 */
import { spawn, ChildProcess } from 'child_process';
import * as path from 'path';

function startWorker(): ChildProcess {
  const workerScript = path.join(__dirname, 'worker.js');
  const worker = spawn(process.execPath, [workerScript], {
    stdio: 'inherit',
    env: process.env,
  });

  worker.on('error', (err) => {
    console.error('Worker process error:', err);
  });

  return worker;
}

async function runClient(): Promise<void> {
  // Dynamically require so the worker has time to start first
  const { main } = await import('./client-main');
  await main();
}

async function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function run(): Promise<void> {
  const worker = startWorker();

  // Give the worker a moment to connect and start polling
  await sleep(3000);

  try {
    await runClient();
  } finally {
    // Terminate the worker child process cleanly
    worker.kill('SIGTERM');
  }
}

run().catch((err) => {
  console.error(err);
  process.exit(1);
});

